import{_ as a}from"./plugin-vue_export-helper-c27b6911.js";import{o as e,c as s,a as l}from"./app-37e6cb78.js";const n={},k=l('<h1 id="bevezetes" tabindex="-1"><a class="header-anchor" href="#bevezetes" aria-hidden="true">#</a> Bevezetés</h1><p>A Java nyelv régóta az egyik legnépszerűbb és legelterjedtebb programozási nyelv a világon. Java alkalmazásokat a kis méretű mobilalkalmazásoktól kezdve a komplex, vállalati szintű rendszerekig tervezhetjük és fejleszthetjük. A Java Backend programozás különösen izgalmas és fontos része ennek a sokoldalú nyelvnek.</p><p>Ebben a cikkben arról fogunk beszélni, hogy mi is pontosan a Java Backend programozás, és milyen lépések szükségesek ahhoz, hogy sikeresen fejlesszünk Java alapú szerveroldali alkalmazásokat. A témakör fokozatosan épül fel, kezdve a Java alapjainak ismétlésével, majd a modern Java keretrendszerekbe, például a JavaFX-be, a Maven projektkezelésbe és a Spring Boot alkalmazások készítésébe történő bevezetéssel.</p><h2 id="java-alapjai" tabindex="-1"><a class="header-anchor" href="#java-alapjai" aria-hidden="true">#</a> Java alapjai</h2><p>A Java Backend programozás alapjai az egyszerű Java programozással kezdődnek. Ebben a részben röviden áttekintjük a Java nyelv alapjait, beleértve a változók, az osztályok, az objektumok és a metódusok használatát. Ismétlésül fogjuk felidézni, hogyan működik a Java nyelv, és hogyan épül fel a Java alkalmazás.</p><h2 id="javafx-es-grafikus-felhasznaloi-feluletek" tabindex="-1"><a class="header-anchor" href="#javafx-es-grafikus-felhasznaloi-feluletek" aria-hidden="true">#</a> JavaFX és grafikus felhasználói felületek</h2><p>A JavaFX egy korszerű grafikus felhasználói felület (GUI) keretrendszer, amely lehetővé teszi számunkra, hogy elegáns és felhasználóbarát grafikus alkalmazásokat fejlesszünk. Ebben a részben megismerkedünk a JavaFX alapjaival, és bemutatjuk, hogyan hozhatunk létre interaktív és vonzó grafikus felhasználói felületeket.</p><h2 id="maven-projektkezeles" tabindex="-1"><a class="header-anchor" href="#maven-projektkezeles" aria-hidden="true">#</a> Maven projektkezelés</h2><p>A Maven egy projektkezelő eszköz, amely segít a Java alkalmazások fejlesztésében és menedzselésében. Megtanuljuk, hogyan hozzunk létre Maven projektet, és hogyan használjuk a függőségek kezelésére, így könnyen és hatékonyan dolgozhatunk a Java projekteinkkel.</p><h2 id="spring-boot-es-restful-api-k" tabindex="-1"><a class="header-anchor" href="#spring-boot-es-restful-api-k" aria-hidden="true">#</a> Spring Boot és RESTful API-k</h2><p>A Spring Boot egy kiváló keretrendszer a gyors és hatékony Java alkalmazások fejlesztéséhez. Ebben a részben bemutatjuk, hogyan készítsünk RESTful API-kat Spring Boot segítségével. Megismerkedünk a mikroszolgáltatások és a webalkalmazások fejlesztésének alapjaival, és hogyan használjuk a Spring Bootot az alkalmazások építéséhez.</p><p>Kezdjük a Java világának felfedezését, és lépjünk tovább a modern és hatékony alkalmazások fejlesztésének útján.</p>',12),t=[k];function o(r,i){return e(),s("div",null,t)}const d=a(n,[["render",o],["__file","index.html.vue"]]);export{d as default};
